#include <bits/stdc++.h>
using namespace std;
int main() {
	long long n, k, T, a[10000001], maxa, art;
	cin >> T;
	for (long long i = 0; i < T; i++) {
		cin >> n >> k;
		for (long long i = 0; i < n; i++) {
			cin >> a[i];
		}
		maxa = 0;
		art = 0;
		if (k >= 1 ) {
			if (n != 2) {
				for (long long i = 0; i < n; i++) {
					maxa = max(maxa, a[i]);
				}
				cout << maxa*n << "\n";
			} else {
				if ( k % 2 != 0) {
					a[0] = a[1] + a[0];
					a[1] = a[0] - a[1];
					a[0] = a[0] - a[1];
					for (int i = 0; i < n; i++) {
						maxa = max(maxa, a[i]);
						art += maxa;
					}
					cout << art << "\n";
				} else {
					for (long long i = 0; i < n; i++) {
						maxa = max(maxa, a[i]);
						art += maxa;
					}
					cout << art << "\n";
				}

			}

		} else {
			for (long long i = 0; i < n; i++) {
				maxa = max(maxa, a[i]);
				art += maxa;
			}
			cout << art << "\n";
		}

	}


	return 0;
}
